import os
import re
import json

def find_struct_with_typemeta(file_path):
    """Find all struct types that have metav1.TypeMeta embedded."""
    results = []

    try:
        with open(file_path, 'r') as f:
            content = f.read()
    except:
        return results

    # Pattern to find: type Name struct { ... metav1.TypeMeta ... }
    # We need to be careful because Go allows multi-line struct definitions

    # Split by "type " keyword to find type definitions
    lines = content.split('\n')

    i = 0
    while i < len(lines):
        line = lines[i]

        # Look for "type NAME struct {" pattern
        type_match = re.match(r'^\s*type\s+([A-Z]\w*)\s+struct\s*\{', line)

        if type_match:
            struct_name = type_match.group(1)

            # Skip List types
            if 'List' in struct_name:
                i += 1
                continue

            # Now look ahead for metav1.TypeMeta in the next few lines
            has_typemeta = False
            j = i + 1
            brace_count = 1

            while j < len(lines) and brace_count > 0:
                struct_line = lines[j]

                # Count braces to find the end of struct
                brace_count += struct_line.count('{') - struct_line.count('}')

                # Check for metav1.TypeMeta
                if 'metav1.TypeMeta' in struct_line:
                    has_typemeta = True

                if brace_count == 0:
                    break

                j += 1

            if has_typemeta:
                results.append(struct_name)

        i += 1

    return results

def main():
    all_implementors = []

    # Find all types.go files in versioned API packages
    api_files = []

    # Scan kubernetes/api repositories
    api_base = "/workspace/api"
    for root, dirs, files in os.walk(api_base):
        # Only look in version directories (v1, v1beta1, etc.)
        if re.search(r'/v[0-9]', root):
            for file in files:
                if file == 'types.go' and 'generated' not in file:
                    api_files.append((root, file, 'kubernetes/api'))

    # Scan kubernetes/apimachinery repositories
    apimachinery_base = "/workspace/apimachinery"
    for root, dirs, files in os.walk(apimachinery_base):
        for file in files:
            if file == 'types.go' and 'generated' not in file:
                # We want types in versioned packages
                if re.search(r'/v[0-9]', root):
                    api_files.append((root, file, 'kubernetes/apimachinery'))

    # Process each file
    for full_path, filename, repo in api_files:
        file_path = os.path.join(full_path, filename)
        struct_names = find_struct_with_typemeta(file_path)

        for struct_name in struct_names:
            # Compute relative path
            if repo == 'kubernetes/api':
                rel_path = os.path.relpath(file_path, '/workspace/api')
            else:
                rel_path = os.path.relpath(file_path, '/workspace/apimachinery')

            all_implementors.append({
                'repo': repo,
                'file': rel_path,
                'struct_name': struct_name
            })

    # Sort by repo, then file, then struct_name
    all_implementors.sort(key=lambda x: (x['repo'], x['file'], x['struct_name']))

    return all_implementors

if __name__ == '__main__':
    results = main()
    for r in results:
        print(json.dumps(r))
